// MARK: - Keychain Helper for Encryption Key Management

final class KeychainHelper {
    
    static let shared = KeychainHelper()
    private init() {}
    
    private let encryptionKeyAccount = "com.app.encryption.key"
    private let encryptionKeyService = "EncryptionKeyService"
    
    /// Retrieves or generates the AES-256 encryption key stored in the Keychain.
    func getOrCreateEncryptionKey() throws -> Data {
        if let existingKey = try? retrieveKey() {
            return existingKey
        }
        
        let newKey = try generateRandomKey(sizeInBytes: 32) // 256-bit key
        try storeKey(newKey)
        return newKey
    }
    
    private func generateRandomKey(sizeInBytes: Int) throws -> Data {
        var keyData = Data(count: sizeInBytes)
        let result = keyData.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, sizeInBytes, buffer.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw SecurityModuleError.keyGenerationFailed
        }
        return keyData
    }
    
    private func storeKey(_ key: Data) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: encryptionKeyService,
            kSecAttrAccount as String: encryptionKeyAccount,
            kSecValueData as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        // Delete any existing item first
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw SecurityModuleError.keychainStoreFailed(status)
        }
    }
    
    private func retrieveKey() throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: encryptionKeyService,
            kSecAttrAccount as String: encryptionKeyAccount,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw SecurityModuleError.keychainRetrieveFailed(status)
        }
        
        return data
    }
    
    func deleteEncryptionKey() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: encryptionKeyService,
            kSecAttrAccount as String: encryptionKeyAccount
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Error Types

enum SecurityModuleError: LocalizedError {
    case keyGenerationFailed
    case keychainStoreFailed(OSStatus)
    case keychainRetrieveFailed(OSStatus)
    case encryptionFailed(String)
    case decryptionFailed(String)
    case invalidData
    case dataSerializationFailed
    
    var errorDescription: String? {
        switch self {
        case .keyGenerationFailed:
            return "Failed to generate encryption key."
        case .keychainStoreFailed(let status):
            return "Failed to store key in Keychain. Status: \(status)"
        case .keychainRetrieveFailed(let status):
            return "Failed to retrieve key from Keychain. Status: \(status)"
        case .encryptionFailed(let detail):
            return "Encryption failed: \(detail)"
        case .decryptionFailed(let detail):
            return "Decryption failed: \(detail)"
        case .invalidData:
            return "Invalid data provided."
        case .dataSerializationFailed:
            return "Data serialization/deserialization failed."
        }
    }
}

// MARK: - AES Encryption Engine

final class AESCryptoEngine {
    
    /// Encrypts data using AES-256-GCM via CryptoKit-style approach with CommonCrypto fallback.
    /// Format: [IV (12 bytes)] + [ciphertext] + [tag (16 bytes)] when using GCM
    /// Fallback: AES-256-CBC with PKCS7 padding. Format: [IV (16 bytes)] + [ciphertext]
    
    static func encrypt(data: Data, key: Data) throws -> Data {
        guard key.count == kCCKeySizeAES256 else {
            throw SecurityModuleError.encryptionFailed("Invalid key size. Expected 32 bytes.")
        }
        
        // Generate random IV
        let ivSize = kCCBlockSizeAES128
        var iv = Data(count: ivSize)
        let ivResult = iv.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, ivSize, buffer.baseAddress!)
        }
        guard ivResult == errSecSuccess else {
            throw SecurityModuleError.encryptionFailed("Failed to generate IV.")
        }
        
        // AES-256-CBC with PKCS7 padding
        let bufferSize = data.count + kCCBlockSizeAES128
        var encryptedData = Data(count: bufferSize)
        var numBytesEncrypted: size_t = 0
        
        let cryptStatus = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                data.withUnsafeBytes { dataBytes in
                    encryptedData.withUnsafeMutableBytes { encryptedBytes in
                        CCCrypt(
                            CCOperation(kCCEncrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress, key.count,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress, data.count,
                            encryptedBytes.baseAddress, bufferSize,
                            &numBytesEncrypted
                        )
                    }
                }
            }
        }
        
        guard cryptStatus == kCCSuccess else {
            throw SecurityModuleError.encryptionFailed("CCCrypt returned status \(cryptStatus)")
        }
        
        encryptedData.removeSubrange(numBytesEncrypted..<encryptedData.count)
        
        // Compute HMAC-SHA256 over IV + ciphertext for integrity
        var combined = Data()
        combined.append(iv)
        combined.append(encryptedData)
        
        let hmac = try computeHMAC(data: combined, key: key)
        
        // Final format: [IV (16 bytes)] + [ciphertext] + [HMAC (32 bytes)]
        combined.append(hmac)
        
        return combined
    }
    
    static func decrypt(data: Data, key: Data) throws -> Data {
        guard key.count == kCCKeySizeAES256 else {
            throw SecurityModuleError.decryptionFailed("Invalid key size. Expected 32 bytes.")
        }
        
        let ivSize = kCCBlockSizeAES128
        let hmacSize = Int(CC_SHA256_DIGEST_LENGTH)
        
        guard data.count > ivSize + hmacSize else {
            throw SecurityModuleError.decryptionFailed("Data too short to contain IV, ciphertext, and HMAC.")
        }
        
        // Extract components
        let iv = data.prefix(ivSize)
        let hmac = data.suffix(hmacSize)
        let ivAndCiphertext = data.prefix(data.count - hmacSize)
        let ciphertext = data[ivSize..<(data.count - hmacSize)]
        
        // Verify HMAC first (authenticate-then-decrypt)
        let computedHMAC = try computeHMAC(data: ivAndCiphertext, key: key)
        
        guard constantTimeCompare(computedHMAC, Data(hmac)) else {
            throw SecurityModuleError.decryptionFailed("HMAC verification failed. Data may have been tampered with.")
        }
        
        // Decrypt
        let bufferSize = ciphertext.count + kCCBlockSizeAES128
        var decryptedData = Data(count: bufferSize)
        var numBytesDecrypted: size_t = 0
        
        let ciphertextData = Data(ciphertext)
        
        let cryptStatus = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                ciphertextData.withUnsafeBytes { cipherBytes in
                    decryptedData.withUnsafeMutableBytes { decryptedBytes in
                        CCCrypt(
                            CCOperation(kCCDecrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress, key.count,
                            ivBytes.baseAddress,
                            cipherBytes.baseAddress, ciphertextData.count,
                            decryptedBytes.baseAddress, bufferSize,
                            &numBytesDecrypted
                        )
                    }
                }
            }
        }
        
        guard cryptStatus == kCCSuccess else {
            throw SecurityModuleError.decryptionFailed("CCCrypt returned status \(cryptStatus)")
        }
        
        decryptedData.removeSubrange(numBytesDecrypted..<decryptedData.count)
        return decryptedData
    }
    
    // MARK: - HMAC
    
    private static func computeHMAC(data: Data, key: Data) throws -> Data {
        var hmac = Data(count: Int(CC_SHA256_DIGEST_LENGTH))
        
        hmac.withUnsafeMutableBytes { hmacBytes in
            key.withUnsafeBytes { keyBytes in
                data.withUnsafeBytes { dataBytes in
                    CCHmac(
                        CCHmacAlgorithm(kCCHmacAlgSHA256),
                        keyBytes.baseAddress, key.count,
                        dataBytes.baseAddress, data.count,
                        hmacBytes.baseAddress
                    )
                }
            }
        }
        
        return hmac
    }
    
    /// Constant-time comparison to prevent timing attacks
    private static func constantTimeCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else { return false }
        var result: UInt8 = 0
        for (x, y) in zip(a, b) {
            result |= x ^ y
        }
        return result == 0
    }
}

