// MARK: - Secure Data Store

final class SecureDataStore {
    
    static let shared = SecureDataStore()
    
    private let fileManager = FileManager.default
    private let keychainHelper = KeychainHelper.shared
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()
    
    private var encryptionKey: Data?
    
    private init() {
        do {
            encryptionKey = try keychainHelper.getOrCreateEncryptionKey()
        } catch {
            print("SecureDataStore: Failed to initialize encryption key: \(error.localizedDescription)")
        }
    }
    
    // MARK: - Directory Management
    
    private func secureDirectory() throws -> URL {
        let documentsURL = try fileManager.url(
            for: .applicationSupportDirectory,
            in: .userDomainMask,
            appropriateFor: nil,
            create: true
        )
        let secureDir = documentsURL.appendingPathComponent("SecureStore", isDirectory: true)
        
        if !fileManager.fileExists(atPath: secureDir.path) {
            try fileManager.createDirectory(at: secureDir, withIntermediateDirectories: true)
            // Exclude from backups
            var resourceValues = URLResourceValues()
            resourceValues.isExcludedFromBackup = true
            var mutableURL = secureDir
            try mutableURL.setResourceValues(resourceValues)
        }
        
        return secureDir
    }
    
    private func fileURL(for identifier: String) throws -> URL {
        let directory = try secureDirectory()
        // Use a hash of the identifier as filename to avoid leaking info
        let hashedName = sha256Hash(identifier)
        return directory.appendingPathComponent(hashedName)
    }
    
    private func sha256Hash(_ string: String) -> String {
        guard let data = string.data(using: .utf8) else { return string }
        var hash = Data(count: Int(CC_SHA256_DIGEST_LENGTH))
        hash.withUnsafeMutableBytes { hashBytes in
            data.withUnsafeBytes { dataBytes in
                _ = CC_SHA256(dataBytes.baseAddress, CC_LONG(data.count), hashBytes.bindMemory(to: UInt8.self).baseAddress)
            }
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
    
    // MARK: - Generic Encrypt & Store
    
    private func encryptAndStore<T: Encodable>(_ object: T, identifier: String) throws {
        guard let key = encryptionKey else {
            throw SecurityModuleError.encryptionFailed("Encryption key not available.")
        }
        
        let jsonData = try encoder.encode(object)
        let encryptedData = try AESCryptoEngine.encrypt(data: jsonData, key: key)
        
        let url = try fileURL(for: identifier)
        try encryptedData.write(to: url, options: [.atomic, .completeFileProtection])
    }
    
    private func retrieveAndDecrypt<T: Decodable>(_ type: T.Type, identifier: String) throws -> T {
        guard let key = encryptionKey else {
            throw SecurityModuleError.decryptionFailed("Encryption key not available.")
        }
        
        let url = try fileURL(for: identifier)
        let encryptedData = try Data(contentsOf: url)
        let decryptedData = try AESCryptoEngine.decrypt(data: encryptedData, key: key)
        
        return try decoder.decode(type, from: decryptedData)
    }
    
    private func deleteStoredData(identifier: String) throws {
        let url = try fileURL(for: identifier)
        if fileManager.fileExists(atPath: url.path) {
            // Overwrite with random data before deleting (secure erase)
            if let fileSize = try? fileManager.attributesOfItem(atPath: url.path)[.size] as? Int, fileSize > 0 {
                var randomData = Data(count: fileSize)
                randomData.withUnsafeMutableBytes { buffer in
                    _ = SecRandomCopyBytes(kSecRandomDefault, fileSize, buffer.baseAddress!)
                }
                try? randomData.write(to: url, options: .atomic)
            }
            try fileManager.removeItem(at: url)
        }
    }
    
    // MARK: - User Credentials
    
    func storeCredentials(_ credentials: UserCredentials, forUser userId: String) throws {
        try encryptAndStore(credentials, identifier: "credentials_\(userId)")
    }
    
    func retrieveCredentials(forUser userId: String) throws -> UserCredentials {
        return try retrieveAndDecrypt(UserCredentials.self, identifier: "credentials_\(userId)")
    }
    
    func deleteCredentials(forUser userId: String) throws {
        try deleteStoredData(identifier: "credentials_\(userId)")
    }
    
    // MARK: - Payment Tokens
    
    func storePaymentToken(_ token: PaymentToken, forUser userId: String) throws {
        // Support multiple payment tokens
        var tokens = (try? retrievePaymentTokens(forUser: userId)) ?? []
        tokens.removeAll { $0.tokenId == token.tokenId }
        tokens.append(token)
        try encryptAndStore(tokens, identifier: "payment_\(userId)")
    }
    
    func retrievePaymentTokens(forUser userId: String) throws -> [PaymentToken] {
        return try retrieveAndDecrypt([PaymentToken].self, identifier: "payment_\(userId)")
    }
    
    func deletePaymentTokens(forUser userId: String) throws {
        try deleteStoredData(identifier: "payment_\(userId)")
    }
    
    // MARK: - Personal Information
    
    func storePersonalInfo(_ info: PersonalInformation, forUser userId: String) throws {
        try encryptAndStore(info, identifier: "personal_\(userId)")
    }
    
    func retrievePersonalInfo(forUser userId: String) throws -> PersonalInformation {
        return try retrieveAndDecrypt(PersonalInformation.self, identifier: "personal_\(userId)")
    }
    
    func deletePersonalInfo(forUser userId: String) throws {
        try deleteStoredData(identifier: "personal_\(userId)")
    }
    
    // MARK: - Generic Secure Storage
    
    func storeSecureData<T: Encodable>(_ data: T, withIdentifier identifier: String) throws {
        try encryptAndStore(data, identifier: identifier)
    }
    
    func retrieveSecureData<T: Decodable>(_ type: T.Type, withIdentifier identifier: String) throws -> T {
        return try retrieveAndDecrypt(type, identifier: identifier)
    }
    
    func deleteSecureData(withIdentifier identifier: String) throws {
        try deleteStoredData(identifier: identifier)
    }
    
    // MARK: - Wipe All Data
    
    func wipeAllSecureData() throws {
        let directory = try secureDirectory()
        let contents = try fileManager.contentsOfDirectory(at: directory, includingPropertiesForKeys: nil)
        for fileURL in contents {
            // Overwrite before delete
            if let fileSize = try? fileManager.attributesOfItem(atPath: fileURL.path)[.size] as? Int, fileSize > 0 {
                var randomData = Data(count: fileSize)
                randomData.withUnsafeMutableBytes { buffer in
                    _ = SecRandomCopyBytes(kSecRandomDefault, fileSize, buffer.baseAddress!)
                }
                try? randomData.write(to: fileURL, options: .atomic)
            }
            try fileManager.removeItem(at: fileURL)
        }
    }
    
    /// Rotates the encryption key. Re-encrypts all stored data with a new key.
    func rotateEncryptionKey() throws {
        guard let oldKey = encryptionKey else {
            throw SecurityModuleError.encryptionFailed("No existing encryption key to rotate from.")
        }
        
        let directory = try secureDirectory()
        let contents = try fileManager.contentsOfDirectory(at: directory, includingPropertiesForKeys: nil)
        
        // Decrypt all files with old key
        var decryptedFiles: [(URL, Data)] = []
        for fileURL in contents {
            let encryptedData = try Data(contentsOf: fileURL)
            let decryptedData = try AESCryptoEngine.decrypt(data: encryptedData, key: oldKey)
            decryptedFiles.append((fileURL, decryptedData))
        }
        
        // Generate new key
        keychainHelper.deleteEncryptionKey()
        let newKey = try keychainHelper.getOrCreateEncryptionKey()
        encryptionKey = newKey
        
        // Re-encrypt all files with new key
        for (fileURL, plainData) in decryptedFiles {
            let reEncrypted = try AESCryptoEngine.encrypt(data: plainData, key: newKey)
            try reEncrypted.write(to: fileURL, options: [.atomic, .completeFileProtection])
        }
    }
}

// MARK: - Password Hashing Utility

final class PasswordHasher {
    
    /// Hashes a password using PBKDF2 with a random salt.
    /// Returns a combined string: base64(salt) + ":" + base64(hash)
    static func hashPassword(_ password: String, iterations: UInt32 = 100_000) throws -> String {
        let saltLength = 32
        var salt = Data(count: saltLength)
        let saltResult = salt.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, saltLength, buffer.baseAddress!)
        }
        guard saltResult == errSecSuccess else {
            throw SecurityModuleError.encryptionFailed("Failed to generate salt.")
        }
        
        let hash = try deriveKey(password: password, salt: salt, iterations: iterations)
        
        return salt.base64EncodedString() + ":" + hash.base64EncodedString()
    }
    
    /// Verifies a password against a stored hash string.
    static func verifyPassword(_ password: String, againstHash storedHash: String, iterations: UInt32 = 100_000) throws -> Bool {
        let components = storedHash.split(separator: ":")
        guard components.count == 2,
              let salt = Data(base64Encoded: String(components[0])),
              let expectedHash = Data(base64Encoded: String(components[1])) else {
            throw SecurityModuleError.invalidData
        }
        
        let computedHash = try deriveKey(password: password, salt: salt, iterations: iterations)
        
        // Constant-time comparison
        guard computedHash.count == expectedHash.count else { return false }
        var result: UInt8 = 0
        for (a, b) in zip(computedHash, expectedHash) {
            result |= a ^ b
        }
        return result == 0
    }
    
    private static func deriveKey(password: String, salt: Data, iterations: UInt32, keyLength: Int = 32) throws -> Data {
        guard let passwordData = password.data(using: .utf8) else {
            throw SecurityModuleError.invalidData
        }
        
        var derivedKey = Data(count: keyLength)
        
        let status = derivedKey.withUnsafeMutableBytes { derivedBytes in
            salt.withUnsafeBytes { saltBytes in
                passwordData.withUnsafeBytes { passwordBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.bindMemory(to: Int8.self).baseAddress,
                        passwordData.count,
                        saltBytes.bindMemory(to: UInt8.self).baseAddress,
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        iterations,
                        derivedBytes.bindMemory(to: UInt8.self).baseAddress,
                        keyLength
                    )
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw SecurityModuleError.encryptionFailed("PBKDF2 key derivation failed with status \(status)")
        }
        
        return derivedKey
    }
}

